import React from 'react';
import { COMPANY_FIELD_LABEL } from '../../utils/companyField';
import { useCompanyLabelMap } from '../../hooks/useCompanyLabelMap';

export const CatalogCompanyTh: React.FC = () => (
  <th>{COMPANY_FIELD_LABEL}</th>
);

export interface CatalogCompanyTdProps {
  companyId?: string;
}

export const CatalogCompanyTd: React.FC<CatalogCompanyTdProps> = ({ companyId }) => {
  const { labelFor, sessionCompanyId, loading } = useCompanyLabelMap();
  const id = companyId ?? sessionCompanyId;
  if (loading && !id) return <td>…</td>;
  return <td>{labelFor(id)}</td>;
};
