import type { CustomerDto } from './models';

export function toCreateCustomerPayload(form: Partial<CustomerDto>) {
  return {
    code: form.code,
    name: form.name,
    customerType: form.customerType,
    customerGroupId: form.customerGroupId?.trim() || null,
    taxCode: form.taxCode,
    address: form.address,
    phone: form.phone,
    isActive: form.isActive ?? true,
  };
}

export function toUpdateCustomerPayload(form: Partial<CustomerDto>) {
  return {
    name: form.name,
    customerType: form.customerType,
    customerGroupId: form.customerGroupId?.trim() || null,
    taxCode: form.taxCode,
    address: form.address,
    phone: form.phone,
    isActive: form.isActive ?? true,
  };
}
